import assert from 'node:assert/strict';
import { mkdtempSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import test, { after, before } from 'node:test';

import Fastify, { type FastifyInstance } from 'fastify';

import { HouseholdVoiceCaptureCreatedSchema } from '@lifeos/contracts';
import { type BaseEvent, createEventBusClient, type ManagedEventBus, Topics } from '@lifeos/event-bus';
import { HouseholdGraphClient, generateInviteToken } from '@lifeos/household-identity-module';
import { JwtService } from '@lifeos/security';

import { registerCaptureRoutes } from './capture';

type TestCaptureEntry = {
  id: string;
  content: string;
  type: 'text' | 'voice';
  capturedAt: string;
  source: string;
  tags: string[];
  status: 'pending' | 'triaged';
  metadata?: {
    scope?: 'household';
    householdId?: string;
    source?: 'mobile' | 'ha_satellite' | 'ha_bridge';
    sourceDeviceId?: string;
    targetHint?: 'shopping' | 'chore' | 'reminder' | 'note' | 'unknown';
  };
};

function createInMemoryLifeGraphClient() {
  const captureEntries = new Map<string, TestCaptureEntry>();
  return {
    async appendCaptureEntry(entry: TestCaptureEntry): Promise<void> {
      captureEntries.set(entry.id, entry);
    },
    async getCaptureEntry(id: string): Promise<TestCaptureEntry | undefined> {
      return captureEntries.get(id);
    },
    async loadGraph(): Promise<{ captureEntries: TestCaptureEntry[] }> {
      return { captureEntries: [...captureEntries.values()] };
    },
  };
}

async function waitFor(condition: () => boolean, timeoutMs = 500): Promise<void> {
  const deadline = Date.now() + timeoutMs;
  while (Date.now() < deadline) {
    if (condition()) {
      return;
    }

    await new Promise((resolve) => setTimeout(resolve, 25));
  }

  assert.ok(condition());
}

before(() => {
  process.env.LIFEOS_JWT_SECRET = 'test-jwt-secret';
});

after(() => {
  delete process.env.LIFEOS_JWT_SECRET;
  jwtService = undefined;
});

let jwtService: JwtService | undefined;

function getJwtService(): JwtService {
  if (!jwtService) {
    jwtService = new JwtService();
  }
  return jwtService;
}

async function bearerFor(userId: string): Promise<string> {
  const token = await getJwtService().issue({
    sub: userId,
    service_id: 'dashboard-service',
    scopes: ['service.read'],
  });
  return `Bearer ${token.token}`;
}

function createHarness(): {
  db: HouseholdGraphClient;
  app: FastifyInstance;
  eventBus: ManagedEventBus;
  lifeGraph: ReturnType<typeof createInMemoryLifeGraphClient>;
  cleanup: () => Promise<void>;
} {
  const tempDir = mkdtempSync(join(tmpdir(), 'lifeos-dashboard-capture-'));
  const dbPath = join(tempDir, 'dashboard-household.db');

  const db = new HouseholdGraphClient(dbPath);
  db.initializeSchema();

  const eventBus = createEventBusClient({
    servers: 'nats://127.0.0.1:1',
    timeoutMs: 25,
    maxReconnectAttempts: 0,
  });

  const lifeGraph = createInMemoryLifeGraphClient();

  const app = Fastify();
  registerCaptureRoutes(app, db, eventBus, lifeGraph);

  return {
    db,
    app,
    eventBus,
    lifeGraph,
    cleanup: async () => {
      await app.close();
      await eventBus.close();
      db.close();
      rmSync(tempDir, { recursive: true, force: true });
    },
  };
}

function activateMember(
  db: HouseholdGraphClient,
  householdId: string,
  userId: string,
  role: 'Admin' | 'Adult' | 'Teen' | 'Child' | 'Guest',
  invitedBy: string,
): void {
  db.addMember(householdId, userId, role, invitedBy);
  const token = generateInviteToken();
  const expiresAt = new Date(Date.now() + 60_000).toISOString();
  db.storeInviteToken(householdId, userId, token, expiresAt);
  db.acceptInvite(token, householdId);
}

test('POST /api/capture personal capture returns 201 and publishes no household event', async () => {
  const { app, eventBus, lifeGraph, cleanup } = createHarness();
  const events: Array<BaseEvent<unknown>> = [];

  try {
    await eventBus.subscribe(Topics.lifeos.householdVoiceCaptureCreated, async (event) => {
      events.push(event);
    });

    await app.ready();
    const response = await app.inject({
      method: 'POST',
      url: '/api/capture',
      headers: { authorization: await bearerFor('user-1') },
      payload: {
        type: 'text',
        content: 'remember milk',
        tags: ['shopping'],
      },
    });

    assert.equal(response.statusCode, 201, response.body);
    const body = response.json();
    assert.equal(body.type, 'text');
    assert.equal(body.content, 'remember milk');
    assert.equal(body.status, 'success');

    const persisted = await lifeGraph.getCaptureEntry(body.id as string);
    assert.ok(persisted);
    assert.equal(persisted.metadata, undefined);

    await new Promise((resolve) => setTimeout(resolve, 50));
    assert.equal(events.length, 0);
  } finally {
    await cleanup();
  }
});

test('POST /api/capture household capture returns 201 and publishes household event', async () => {
  const { db, app, eventBus, lifeGraph, cleanup } = createHarness();
  const events: Array<BaseEvent<unknown>> = [];

  try {
    const household = db.createHousehold('Household Capture Home');
    activateMember(db, household.id, 'user-2', 'Adult', 'admin-1');

    await eventBus.subscribe(Topics.lifeos.householdVoiceCaptureCreated, async (event) => {
      events.push(event);
    });

    await app.ready();
    const response = await app.inject({
      method: 'POST',
      url: '/api/capture',
      headers: { authorization: await bearerFor('user-2') },
      payload: {
        type: 'voice',
        content: 'buy apples and dish soap',
        metadata: {
          scope: 'household',
          householdId: household.id,
          source: 'ha_bridge',
          sourceDeviceId: 'kitchen-speaker',
          targetHint: 'shopping',
        },
      },
    });

    assert.equal(response.statusCode, 201, response.body);
    const body = response.json();

    const persisted = await lifeGraph.getCaptureEntry(body.id as string);
    assert.ok(persisted);
    assert.equal(persisted.metadata?.scope, 'household');
    assert.equal(persisted.metadata?.householdId, household.id);
    assert.equal(persisted.metadata?.source, 'ha_bridge');
    assert.equal(persisted.metadata?.sourceDeviceId, 'kitchen-speaker');
    assert.equal(persisted.metadata?.targetHint, 'shopping');

    await waitFor(() => events.length === 1, 800);
    const event = events[0];
    assert.equal(event.type, Topics.lifeos.householdVoiceCaptureCreated);
    const payload = HouseholdVoiceCaptureCreatedSchema.parse(event.data);
    assert.equal(payload.captureId, body.id);
    assert.equal(payload.householdId, household.id);
    assert.equal(payload.actorUserId, 'user-2');
    assert.equal(payload.text, 'buy apples and dish soap');
    assert.equal(payload.audioRef, null);
    assert.equal(payload.source, 'ha_bridge');
    assert.equal(payload.sourceDeviceId, 'kitchen-speaker');
    assert.equal(payload.targetHint, 'shopping');
  } finally {
    await cleanup();
  }
});

test('POST /api/capture household capture for non-member returns 403 and does not persist or publish', async () => {
  const { db, app, eventBus, lifeGraph, cleanup } = createHarness();
  const events: Array<BaseEvent<unknown>> = [];

  try {
    const household = db.createHousehold('Forbidden Household');
    activateMember(db, household.id, 'member-1', 'Adult', 'admin-1');

    await eventBus.subscribe(Topics.lifeos.householdVoiceCaptureCreated, async (event) => {
      events.push(event);
    });

    await app.ready();
    const response = await app.inject({
      method: 'POST',
      url: '/api/capture',
      headers: { authorization: await bearerFor('outsider-1') },
      payload: {
        type: 'text',
        content: 'this should not be accepted',
        metadata: {
          scope: 'household',
          householdId: household.id,
          source: 'mobile',
        },
      },
    });

    assert.equal(response.statusCode, 403, response.body);

    const graph = await lifeGraph.loadGraph();
    assert.equal((graph.captureEntries ?? []).length, 0);

    await new Promise((resolve) => setTimeout(resolve, 50));
    assert.equal(events.length, 0);
  } finally {
    await cleanup();
  }
});

test('POST /api/capture household scope without householdId returns 400', async () => {
  const { app, cleanup } = createHarness();

  try {
    await app.ready();
    const response = await app.inject({
      method: 'POST',
      url: '/api/capture',
      headers: { authorization: await bearerFor('user-3') },
      payload: {
        type: 'text',
        content: 'forgot household id',
        metadata: {
          scope: 'household',
          source: 'mobile',
        },
      },
    });

    assert.equal(response.statusCode, 400, response.body);
    assert.equal(response.json().error, 'householdId is required for household scope');
  } finally {
    await cleanup();
  }
});

test('POST /api/capture household scope with invalid householdId returns 400', async () => {
  const { app, cleanup } = createHarness();

  try {
    await app.ready();
    const response = await app.inject({
      method: 'POST',
      url: '/api/capture',
      headers: { authorization: await bearerFor('user-3b') },
      payload: {
        type: 'text',
        content: 'unknown household',
        metadata: {
          scope: 'household',
          householdId: 'household-does-not-exist',
          source: 'mobile',
        },
      },
    });

    assert.equal(response.statusCode, 400, response.body);
    assert.equal(response.json().error, 'Invalid householdId');
  } finally {
    await cleanup();
  }
});

test('POST /api/capture without auth returns 401', async () => {
  const { app, cleanup } = createHarness();

  try {
    await app.ready();
    const response = await app.inject({
      method: 'POST',
      url: '/api/capture',
      payload: {
        type: 'text',
        content: 'unauthorized',
      },
    });

    assert.equal(response.statusCode, 401, response.body);
  } finally {
    await cleanup();
  }
});

test('POST /api/capture malformed body returns 400', async () => {
  const { app, cleanup } = createHarness();

  try {
    await app.ready();
    const response = await app.inject({
      method: 'POST',
      url: '/api/capture',
      headers: { authorization: await bearerFor('user-4') },
      payload: {
        type: 'text',
        content: '',
      },
    });

    assert.equal(response.statusCode, 400, response.body);
  } finally {
    await cleanup();
  }
});

/**
 * Authentication-related types for the LifeOS mobile SDK.
 */

import { z } from 'zod';

export interface UserProfile {
  id: string;
  email: string;
  displayName: string;
}

export const LoginRequestSchema = z.object({
  email: z.email(),
  password: z.string().min(8),
});

export type LoginRequest = z.infer<typeof LoginRequestSchema>;

export interface AuthTokens {
  accessToken: string;
  refreshToken: string;
}

/**
 * Data capture contracts shared across clients.
 */

import { z } from 'zod';

export const CaptureTypeSchema = z.enum(['text', 'voice']);
export type CaptureType = z.infer<typeof CaptureTypeSchema>;

export const CaptureRequestSchema = z.object({
  type: CaptureTypeSchema,
  content: z.string(),
  metadata: z
    .object({
      scope: z.literal('household').optional(),
      householdId: z.string().min(1).optional(),
      source: z.enum(['mobile', 'ha_satellite', 'ha_bridge']).optional(),
      sourceDeviceId: z.string().min(1).optional(),
      targetHint: z.enum(['shopping', 'chore', 'reminder', 'note', 'unknown']).optional(),
      audioBase64: z.string().optional(),
      durationMs: z.number().optional(),
    })
    .optional(),
  tags: z.array(z.string().min(1)).optional(),
});
export type CaptureRequest = z.infer<typeof CaptureRequestSchema>;
export type CaptureRequestMetadata = z.infer<
  NonNullable<typeof CaptureRequestSchema.shape.metadata>
>;

export const CaptureStatusSchema = z.enum(['success', 'pending', 'failed']);
export type CaptureStatus = z.infer<typeof CaptureStatusSchema>;

export const CaptureResultSchema = z.object({
  id: z.string().min(1),
  type: CaptureTypeSchema,
  content: z.string().min(1),
  processedAt: z.number().int().nonnegative(),
  status: CaptureStatusSchema,
  error: z.string().min(1).optional(),
});
export type CaptureResult = z.infer<typeof CaptureResultSchema>;

export const CaptureListItemSchema = z.object({
  id: z.string().min(1),
  content: z.string().min(1),
  type: z.string().min(1),
  capturedAt: z.string().min(1),
  source: z.string().min(1),
  tags: z.array(z.string()),
  status: z.string().min(1),
});
export type CaptureListItem = z.infer<typeof CaptureListItemSchema>;

import { z } from 'zod';

import { IsoDateTimeSchema } from './loop/shared';

export const HouseholdRoleSchema = z.enum(['Admin', 'Adult', 'Teen', 'Child', 'Guest']);
export type HouseholdRole = z.infer<typeof HouseholdRoleSchema>;

export const HouseholdMemberStatusSchema = z.enum(['active', 'invited', 'suspended']);
export type HouseholdMemberStatus = z.infer<typeof HouseholdMemberStatusSchema>;

export const ChoreStatusSchema = z.enum(['pending', 'in_progress', 'completed', 'skipped']);
export type ChoreStatus = z.infer<typeof ChoreStatusSchema>;

export const ShoppingItemStatusSchema = z.enum(['added', 'in_cart', 'purchased']);
export type ShoppingItemStatus = z.infer<typeof ShoppingItemStatusSchema>;

export const HouseholdCreateRequestSchema = z.object({
  name: z.string().min(1),
});
export type HouseholdCreateRequest = z.infer<typeof HouseholdCreateRequestSchema>;

export const HouseholdInviteMemberRequestSchema = z.object({
  invitedUserId: z.string().min(1),
  role: HouseholdRoleSchema,
});
export type HouseholdInviteMemberRequest = z.infer<typeof HouseholdInviteMemberRequestSchema>;

export const HouseholdJoinRequestSchema = z.object({
  inviteToken: z.string().min(1),
});
export type HouseholdJoinRequest = z.infer<typeof HouseholdJoinRequestSchema>;

export const HouseholdChangeMemberRoleRequestSchema = z.object({
  role: HouseholdRoleSchema,
});
export type HouseholdChangeMemberRoleRequest = z.infer<
  typeof HouseholdChangeMemberRoleRequestSchema
>;

export const HouseholdAddShoppingItemRequestSchema = z.object({
  listId: z.string().min(1).optional(),
  title: z.string().min(1),
  source: z.enum(['manual', 'voice', 'routine']),
});
export type HouseholdAddShoppingItemRequest = z.infer<typeof HouseholdAddShoppingItemRequestSchema>;

export const HouseholdUpdateShoppingItemStatusRequestSchema = z.object({
  status: ShoppingItemStatusSchema,
});
export type HouseholdUpdateShoppingItemStatusRequest = z.infer<
  typeof HouseholdUpdateShoppingItemStatusRequestSchema
>;

export const HouseholdCreateChoreRequestSchema = z.object({
  title: z.string().min(1),
  assignedToUserId: z.string().min(1),
  dueAt: IsoDateTimeSchema,
  recurrenceRule: z.string().optional(),
});
export type HouseholdCreateChoreRequest = z.infer<typeof HouseholdCreateChoreRequestSchema>;

export const HouseholdCreateReminderRequestSchema = z.object({
  objectType: z.string().min(1),
  objectId: z.string().min(1),
  targetUserIds: z.array(z.string().min(1)),
  remindAt: IsoDateTimeSchema,
});
export type HouseholdCreateReminderRequest = z.infer<typeof HouseholdCreateReminderRequestSchema>;

export const HouseholdCreateNoteRequestSchema = z.object({
  body: z.string().min(1),
});
export type HouseholdCreateNoteRequest = z.infer<typeof HouseholdCreateNoteRequestSchema>;

export const HouseholdMemberInvitedSchema = z.object({
  householdId: z.string().min(1),
  invitedUserId: z.string().min(1),
  role: HouseholdRoleSchema,
  inviteToken: z.string().min(1),
  expiresAt: IsoDateTimeSchema,
});
export type HouseholdMemberInvited = z.infer<typeof HouseholdMemberInvitedSchema>;

export const HouseholdMemberJoinedSchema = z.object({
  householdId: z.string().min(1),
  userId: z.string().min(1),
  role: HouseholdRoleSchema,
  joinedAt: IsoDateTimeSchema,
});
export type HouseholdMemberJoined = z.infer<typeof HouseholdMemberJoinedSchema>;

export const HouseholdMemberRoleChangedSchema = z.object({
  householdId: z.string().min(1),
  userId: z.string().min(1),
  previousRole: HouseholdRoleSchema,
  newRole: HouseholdRoleSchema,
});
export type HouseholdMemberRoleChanged = z.infer<typeof HouseholdMemberRoleChangedSchema>;

export const HouseholdChoreAssignedSchema = z.object({
  householdId: z.string().min(1),
  choreId: z.string().min(1),
  choreTitle: z.string().min(1),
  assignedToUserId: z.string().min(1),
  dueAt: IsoDateTimeSchema,
  recurrenceRule: z.string().optional(),
});
export type HouseholdChoreAssigned = z.infer<typeof HouseholdChoreAssignedSchema>;

export const HouseholdChoreCompletedSchema = z.object({
  householdId: z.string().min(1),
  choreId: z.string().min(1),
  choreTitle: z.string().min(1),
  completedByUserId: z.string().min(1),
  completedAt: IsoDateTimeSchema,
  streakCount: z.number().int().nonnegative(),
});
export type HouseholdChoreCompleted = z.infer<typeof HouseholdChoreCompletedSchema>;

export const HouseholdShoppingItemAddedSchema = z.object({
  householdId: z.string().min(1),
  listId: z.string().min(1),
  itemId: z.string().min(1),
  title: z.string().min(1),
  addedByUserId: z.string().min(1),
  source: z.enum(['manual', 'voice', 'routine']),
});
export type HouseholdShoppingItemAdded = z.infer<typeof HouseholdShoppingItemAddedSchema>;

export const HouseholdShoppingItemPurchasedSchema = z.object({
  householdId: z.string().min(1),
  listId: z.string().min(1),
  itemId: z.string().min(1),
  title: z.string().min(1),
  purchasedByUserId: z.string().min(1),
  purchasedAt: IsoDateTimeSchema,
});
export type HouseholdShoppingItemPurchased = z.infer<typeof HouseholdShoppingItemPurchasedSchema>;

export const HouseholdCalendarEventCreatedSchema = z.object({
  householdId: z.string().min(1),
  calendarId: z.string().min(1),
  eventId: z.string().min(1),
  title: z.string().min(1),
  startAt: IsoDateTimeSchema,
  endAt: IsoDateTimeSchema,
  recurrenceRule: z.string().optional(),
  reminderAt: IsoDateTimeSchema.optional(),
  attendeeUserIds: z.array(z.string().min(1)),
});
export type HouseholdCalendarEventCreated = z.infer<typeof HouseholdCalendarEventCreatedSchema>;

export const HouseholdVoiceCaptureCreatedSchema = z.object({
  captureId: z.string().min(1),
  householdId: z.string().min(1),
  actorUserId: z.string().min(1),
  text: z.string().min(1),
  audioRef: z.string().min(1).nullable(),
  source: z.enum(['mobile', 'ha_satellite', 'ha_bridge']),
  sourceDeviceId: z.string().min(1).optional(),
  targetHint: z.enum(['shopping', 'chore', 'reminder', 'note', 'unknown']).optional(),
  createdAt: IsoDateTimeSchema,
});
export type HouseholdVoiceCaptureCreated = z.infer<typeof HouseholdVoiceCaptureCreatedSchema>;

export const HomeNodeVoiceSessionStartedSchema = z.object({
  session_id: z.string().min(1),
  household_id: z.string().min(1),
  surface_id: z.string().min(1),
  started_at: IsoDateTimeSchema,
});
export type HomeNodeVoiceSessionStarted = z.infer<typeof HomeNodeVoiceSessionStartedSchema>;

export const HomeNodeVoiceSessionCompletedSchema = z.object({
  session_id: z.string().min(1),
  household_id: z.string().min(1),
  surface_id: z.string().min(1),
  capture_id: z.string().min(1),
  transcript: z.string().min(1),
  target_hint: z.enum(['shopping', 'chore', 'reminder', 'note', 'unknown']).optional(),
  completed_at: IsoDateTimeSchema,
});
export type HomeNodeVoiceSessionCompleted = z.infer<typeof HomeNodeVoiceSessionCompletedSchema>;

export const HomeNodeVoiceSessionFailedSchema = z.object({
  session_id: z.string().min(1),
  household_id: z.string().min(1),
  surface_id: z.string().min(1),
  reason: z.string().min(1),
  detail: z.string().min(1).optional(),
  failed_at: IsoDateTimeSchema,
});
export type HomeNodeVoiceSessionFailed = z.infer<typeof HomeNodeVoiceSessionFailedSchema>;

export const HouseholdShoppingItemAddRequestedSchema = z.object({
  householdId: z.string().min(1),
  actorUserId: z.string().min(1),
  originalCaptureId: z.string().min(1),
  text: z.string().min(1),
  itemTitle: z.string().min(1),
});
export type HouseholdShoppingItemAddRequested = z.infer<
  typeof HouseholdShoppingItemAddRequestedSchema
>;

export const HouseholdChoreCreateRequestedSchema = z.object({
  householdId: z.string().min(1),
  actorUserId: z.string().min(1),
  originalCaptureId: z.string().min(1),
  text: z.string().min(1),
  choreTitle: z.string().min(1),
});
export type HouseholdChoreCreateRequested = z.infer<typeof HouseholdChoreCreateRequestedSchema>;

export const HouseholdReminderCreateRequestedSchema = z.object({
  householdId: z.string().min(1),
  actorUserId: z.string().min(1),
  originalCaptureId: z.string().min(1),
  text: z.string().min(1),
  reminderText: z.string().min(1),
});
export type HouseholdReminderCreateRequested = z.infer<
  typeof HouseholdReminderCreateRequestedSchema
>;

export const HouseholdNoteCreateRequestedSchema = z.object({
  householdId: z.string().min(1),
  actorUserId: z.string().min(1),
  originalCaptureId: z.string().min(1),
  text: z.string().min(1),
  noteBody: z.string().min(1),
});
export type HouseholdNoteCreateRequested = z.infer<typeof HouseholdNoteCreateRequestedSchema>;

export const HouseholdCaptureUnresolvedSchema = z.object({
  captureId: z.string().min(1),
  householdId: z.string().min(1),
  text: z.string().min(1),
  reason: z.string().min(1),
});
export type HouseholdCaptureUnresolved = z.infer<typeof HouseholdCaptureUnresolvedSchema>;

export const HouseholdAutomationFailedSchema = z.object({
  household_id: z.string().min(1),
  actor_id: z.string().min(1),
  action_type: z.string().min(1),
  error_code: z.string().min(1),
  fix_suggestion: z.string().min(1),
  span_id: z.string().min(1),
  trace_id: z.string().min(1).optional(),
  object_id: z.string().min(1).optional(),
  object_ref: z.string().min(1).optional(),
  details: z.record(z.string(), z.unknown()).optional(),
});
export type HouseholdAutomationFailed = z.infer<typeof HouseholdAutomationFailedSchema>;

export const HouseholdCaptureStatusSchema = z.enum(['pending', 'resolved', 'unresolved']);
export type HouseholdCaptureStatus = z.infer<typeof HouseholdCaptureStatusSchema>;

export const HouseholdCaptureStatusResponseSchema = z.object({
  status: HouseholdCaptureStatusSchema,
  resolvedAction: z.string().min(1).optional(),
  objectId: z.string().min(1).optional(),
});
export type HouseholdCaptureStatusResponse = z.infer<typeof HouseholdCaptureStatusResponseSchema>;

export const HouseholdHomeStateChangedSchema = z.object({
  householdId: z.string().min(1),
  deviceId: z.string().min(1),
  stateKey: z.string().min(1),
  previousValue: z.unknown(),
  newValue: z.unknown(),
  source: z.enum(['ha_bridge', 'manual', 'routine']),
  consentVerified: z.boolean(),
});
export type HouseholdHomeStateChanged = z.infer<typeof HouseholdHomeStateChangedSchema>;

export const HouseholdHomeStateConfigSchema = z.object({
  haIntegrationEnabled: z.boolean().optional(),
  haConsentedStateKeys: z.array(z.string().min(1)).optional(),
  timeZone: z.string().optional(),
});
export type HouseholdHomeStateConfig = z.infer<typeof HouseholdHomeStateConfigSchema>;

export const HouseholdUpdateConfigRequestSchema = z
  .object({
    haIntegrationEnabled: z.boolean().optional(),
    haConsentedStateKeys: z.array(z.string().min(1)).optional(),
    timeZone: z
      .string()
      .optional()
      .refine(
        (value) => value === undefined || Intl.supportedValuesOf('timeZone').includes(value),
        {
          message: 'Invalid IANA time zone',
        },
      ),
  })
  .refine(
    (value) =>
      value.haIntegrationEnabled !== undefined ||
      value.haConsentedStateKeys !== undefined ||
      value.timeZone !== undefined,
    {
      message: 'At least one config field is required',
    },
  );
export type HouseholdUpdateConfigRequest = z.infer<typeof HouseholdUpdateConfigRequestSchema>;

export const HouseholdHaWebhookRequestSchema = z
  .object({
    deviceId: z.string().min(1),
    stateKey: z.string().min(1),
    previousValue: z.unknown().optional(),
    newValue: z.unknown(),
    voice_transcript: z.string().min(1).optional(),
    voiceTranscript: z.string().min(1).optional(),
    sourceDeviceId: z.string().min(1).optional(),
    actorUserId: z.string().min(1).optional(),
